    public func createPipeline(_ request: RARAGConfiguration) throws -> rac_handle_t {
        let symbol = try NativeProtoABI.require(
            RAGGeneratedProtoABI.createPipeline,
            named: RAGGeneratedProtoABI.createPipelineName
        )
        var newHandle: rac_handle_t?
        let status = try NativeProtoABI.withSerializedBytes(request) { bytes, size in
            symbol(bytes, size, &newHandle)
        }
        guard status == RAC_SUCCESS, let newHandle else {
            throw SDKException(code: .notInitialized, message: "RAG proto session create failed: \(status)", category: .component)
        }
        return newHandle
    }

    public func ingest(handle: rac_handle_t, _ request: RARAGDocument) throws -> RARAGStatistics {
        return try NativeProtoABI.invoke(
            request,
            on: handle,
            symbol: RAGGeneratedProtoABI.ingest,
            symbolName: RAGGeneratedProtoABI.ingestName,
            responseType: RARAGStatistics.self
        )
    }

    public func query(handle: rac_handle_t, _ request: RARAGQueryOptions) throws -> RARAGResult {
        return try NativeProtoABI.invoke(
            request,
            on: handle,
            symbol: RAGGeneratedProtoABI.query,
            symbolName: RAGGeneratedProtoABI.queryName,
            responseType: RARAGResult.self
        )
    }

    public func clearProto(handle: rac_handle_t) throws -> RARAGStatistics {
        let symbol = try NativeProtoABI.require(
            RAGGeneratedProtoABI.clearProto,
            named: RAGGeneratedProtoABI.clearProtoName
        )
        var outBuffer = rac_proto_buffer_t()
        defer { NativeProtoABI.free(&outBuffer) }
        let status = symbol(handle, &outBuffer)
        guard status == RAC_SUCCESS else {
            let message = outBuffer.error_message.map { String(cString: $0) }
                ?? "Native proto request failed: \(RAGGeneratedProtoABI.clearProtoName) rc=\(status)"
            throw SDKException(code: .processingFailed, message: message, category: .internal)
        }
        return try NativeProtoABI.decode(RARAGStatistics.self, from: outBuffer)
    }

    public func statsProto(handle: rac_handle_t) throws -> RARAGStatistics {
        let symbol = try NativeProtoABI.require(
            RAGGeneratedProtoABI.statsProto,
            named: RAGGeneratedProtoABI.statsProtoName
        )
        var outBuffer = rac_proto_buffer_t()
        defer { NativeProtoABI.free(&outBuffer) }
        let status = symbol(handle, &outBuffer)
        guard status == RAC_SUCCESS else {
            let message = outBuffer.error_message.map { String(cString: $0) }
                ?? "Native proto request failed: \(RAGGeneratedProtoABI.statsProtoName) rc=\(status)"
            throw SDKException(code: .processingFailed, message: message, category: .internal)
        }
        return try NativeProtoABI.decode(RARAGStatistics.self, from: outBuffer)
    }
}

